  // Public API
  window.COSMOSKIN = window.COSMOSKIN || {};
  window.COSMOSKIN.products = PRODUCTS;

  window.COSMOSKIN.getProductBySlug = function (slug) {
    return PRODUCTS.find(p => p.slug === slug) || null;
  };

  window.COSMOSKIN.getProductsByBrand = function (brand) {
    return PRODUCTS.filter(p => p.brand === brand);
  };

  window.COSMOSKIN.getProductsByType = function (type) {
    return PRODUCTS.filter(p => p.productTypes.includes(type));
  };

  window.COSMOSKIN.getProductsByConcern = function (concern) {
    return PRODUCTS.filter(p => p.concerns.includes(concern));
  };

  window.COSMOSKIN.searchProducts = function (query) {
    const q = query.toLowerCase();
    return PRODUCTS.filter(p =>
      p.name.toLowerCase().includes(q) ||
      p.brand.toLowerCase().includes(q) ||
      p.ingredients.some(i => i.toLowerCase().includes(q)) ||
      p.concerns.some(c => c.toLowerCase().includes(q)) ||
      p.skinTypes.some(s => s.toLowerCase().includes(q))
    );
  };

  window.COSMOSKIN.getRecommendations = function (slug, count = 4) {
    const product = window.COSMOSKIN.getProductBySlug(slug);
    if (!product) return [];
    return product.recommendations
      .slice(0, count)
      .map(s => window.COSMOSKIN.getProductBySlug(s))
      .filter(Boolean);
  };

